import * as fs from 'fs';

type TokenType = 'Number' | 'UnaryPlus' | 'UnaryMinus' | 'Add' | 'Sub' | 'Mul' | 'Div' | 'LParen' | 'RParen';

interface Token {
    type: TokenType;
    value?: number;
}

function tokenize(s: string): Token[] {
    const tokens: Token[] = [];
    let i = 0;
    while (i < s.length) {
        const c = s[i];
        if (c === ' ') {
            i++;
            continue;
        }
        if (c >= '0' && c <= '9') {
            let num = 0;
            while (i < s.length && s[i] >= '0' && s[i] <= '9') {
                num = num * 10 + (s[i] - '0');
                i++;
            }
            tokens.push({ type: 'Number', value: num });
            continue;
        }
        if (c === '(') {
            tokens.push({ type: 'LParen' });
            i++;
            continue;
        }
        if (c === ')') {
            tokens.push({ type: 'RParen' });
            i++;
            continue;
        }
        if (c === '*') {
            tokens.push({ type: 'Mul' });
            i++;
            continue;
        }
        if (c === '/') {
            tokens.push({ type: 'Div' });
            i++;
            continue;
        }
        if (c === '+' || c === '-') {
            let isUnary = false;
            if (tokens.length === 0) {
                isUnary = true;
            } else {
                const last = tokens[tokens.length - 1];
                if (last.type === 'Mul' || last.type === 'Div' || last.type === 'Add' || last.type === 'Sub' || last.type === 'UnaryPlus' || last.type === 'UnaryMinus' || last.type === 'LParen') {
                    isUnary = true;
                }
            }
            if (isUnary) {
                if (c === '+') {
                    tokens.push({ type: 'UnaryPlus' });
                } else {
                    tokens.push({ type: 'UnaryMinus' });
                }
            } else {
                if (c === '+') {
                    tokens.push({ type: 'Add' });
                } else {
                    tokens.push({ type: 'Sub' });
                }
            }
            i++;
            continue;
        }
        // Ignore other characters, though problem says only integers, spaces, parentheses, + - * /
        i++;
    }
    return tokens;
}
```

Now, the shunting-yard algorithm.

```typescript
function getPrecedence(type: TokenType): number {
    if (type === 'UnaryPlus' || type === 'UnaryMinus') return 4;
    if (type === 'Mul' || type === 'Div') return 3;
    if (type === 'Add' || type === 'Sub') return 2;
    return 0;
}

function isLeftAssociative(type: TokenType): boolean {
    return type !== 'UnaryPlus' && type !== 'UnaryMinus';
}

function shuntingYard(tokens: Token[]): Token[] {
    const output: Token[] = [];
    const opStack: Token[] = [];

    for (const token of tokens) {
        if (token.type === 'Number') {
            output.push(token);
        } else if (token.type === 'LParen') {
            opStack.push(token);
        } else if (token.type === 'RParen') {
            while (opStack.length > 0 && opStack[opStack.length - 1].type !== 'LParen') {
                output.push(opStack.pop() as Token);
            }
            if (opStack.length > 0) {
                opStack.pop(); // pop LParen
            }
        } else {
            // Operator
            while (opStack.length > 0) {
                const top = opStack[opStack.length - 1];
                if (top.type === 'LParen') break;

                const p1 = getPrecedence(token.type);
                const p2 = getPrecedence(top.type);
                const leftAssoc = isLeftAssociative(token.type);

                if (leftAssoc && p1 <= p2) {
                    output.push(opStack.pop() as Token);
                } else if (!leftAssoc && p1 < p2) {
                    output.push(opStack.pop() as Token);
                } else {
                    break;
                }
            }
            opStack.push(token);
        }
    }

    while (opStack.length > 0) {
        output.push(opStack.pop() as Token);
    }

    return output;
}
```

