```typescript
function evaluateRPN(rpn: Token[]): number {
    const stack: number[] = [];

    for (const token of rpn) {
        if (token.type === 'Number') {
            stack.push(token.value!);
        } else if (token.type === 'UnaryPlus') {
            const a = stack.pop()!;
            stack.push(a);
        } else if (token.type === 'UnaryMinus') {
            const a = stack.pop()!;
            stack.push(-a);
        } else if (token.type === 'Add') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a + b);
        } else if (token.type === 'Sub') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a - b);
        } else if (token.type === 'Mul') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a * b);
        } else if (token.type === 'Div') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(Math.trunc(a / b));
        }
    }

    return stack[0];
}
```

