    if (type === 'Mul' || type === 'Div') return 3;
    if (type === 'Add' || type === 'Sub') return 2;
    return 0;
}

function isLeftAssociative(type: TokenType): boolean {
    return type !== 'UnaryPlus' && type !== 'UnaryMinus';
}

function shuntingYard(tokens: Token[]): Token[] {
    const output: Token[] = [];
    const opStack: Token[] = [];

    for (const token of tokens) {
        if (token.type === 'Number') {
            output.push(token);
        } else if (token.type === 'LParen') {
            opStack.push(token);
        } else if (token.type === 'RParen') {
            while (opStack.length > 0 && opStack[opStack.length - 1].type !== 'LParen') {
                output.push(opStack.pop() as Token);
            }
            if (opStack.length > 0) {
                opStack.pop(); // pop LParen
            }
        } else {
            while (opStack.length > 0) {
                const top = opStack[opStack.length - 1];
                if (top.type === 'LParen') break;

                const p1 = getPrecedence(token.type);
                const p2 = getPrecedence(top.type);
                const leftAssoc = isLeftAssociative(token.type);

                if (leftAssoc && p1 <= p2) {
                    output.push(opStack.pop() as Token);
                } else if (!leftAssoc && p1 < p2) {
                    output.push(opStack.pop() as Token);
                } else {
                    break;
                }
            }
            opStack.push(token);
        }
    }

    while (opStack.length > 0) {
        output.push(opStack.pop() as Token);
    }

    return output;
}

function evaluateRPN(rpn: Token[]): number {
    const stack: number[] = [];

    for (const token of rpn) {
        if (token.type === 'Number') {
            stack.push(token.value!);
        } else if (token.type === 'UnaryPlus') {
            const a = stack.pop()!;
            stack.push(a);
        } else if (token.type === 'UnaryMinus') {
            const a = stack.pop()!;
            stack.push(-a);
        } else if (token.type === 'Add') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a + b);
        } else if (token.type === 'Sub') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a - b);
        } else if (token.type === 'Mul') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a * b);
        } else if (token.type === 'Div') {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(Math.trunc(a / b));
        }
    }

    return stack[0];
}

